commands.cmd:
raw=$(ss -tlnp) || { echo "ss failed" >&2; exit 1; }
printf '%s\n' "$raw" | awk '
  function esc(s){ gsub(/\\/,"\\\\",s); gsub(/"/,"\\\"",s); return s }
  BEGIN{ printf "{\"results\":["; sep="" }
  NR>1 {
    local=$4
    # port = substring after the last colon; addr = the rest.
    n=split(local, parts, ":"); port=parts[n]
    addr=substr(local, 1, length(local)-length(port)-1)
    wildcard=(addr=="0.0.0.0" || addr=="*" || addr=="[::]" || addr=="::") ? "true" : "false"
    proc=""
    if (match($0, /users:\(\("[^"]+"/)) {
      seg=substr($0, RSTART, RLENGTH)
      sub(/users:\(\(\"/, "", seg); sub(/\"$/, "", seg)
      proc=seg
    }
    printf "%s{\"address\":\"%s\",\"port\":%d,\"wildcard\":%s,\"process\":\"%s\"}",
      sep, esc(addr), port, wildcard, esc(proc)
    sep=","
  }
  END{ printf "]}" }
' || exit 1
